sections.css:
.stack {
  --gap: var(--spacing-400, 1rem);
  display: flex;
  flex-direction: column;
  gap: var(--gap);
}
.bcn-status-chip {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-150);
  padding: 2px var(--spacing-250);
  border-radius: var(--radius-full);
  font-size: var(--type-size-100);
  font-weight: var(--font-weight-semibold);
  white-space: nowrap;
  background: color-mix(in srgb, var(--_chip) 16%, transparent);
  color: color-mix(in srgb, var(--_chip) 72%, #1a1a1a);
}
.bcn-status-chip__dot {
  width: 8px;
  height: 8px;
  border-radius: var(--radius-full);
  background: var(--_chip);
  flex-shrink: 0;
}
.bcn-key-value {
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.bcn-key-value__key {
  font-size: var(--form-font-size-md);
  font-weight: var(--font-weight-medium);
  color: var(--form-label-color);
}
.bcn-key-value__val {
  font-size: var(--form-font-size-md);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.esa-icon {
  --_icon-size: var(--icon-size-md, var(--icon-size-medium, 20px));
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: var(--_icon-size);
  height: var(--_icon-size);
  line-height: 1;
  color: inherit;
}
.esa-icon--sm {
  --_icon-size: var(--icon-size-sm, var(--icon-size-small, 16px));
}
.esa-icon svg {
  display: block;
  width: var(--_icon-size);
  height: var(--_icon-size);
}
.esa-collapsible {
  border: 1px solid var(--collapsible-border-color, var(--color-border, #e5e5e5));
  border-radius: var(--collapsible-radius, var(--radius-300, 0.5rem));
  background: var(--collapsible-bg, var(--color-surface, #fff));
}
.esa-collapsible--flush {
  border: none;
  border-radius: 0;
  background: transparent;
}
.esa-collapsible__summary {
  display: flex;
  align-items: center;
  gap: var(--spacing-200, 0.5rem);
  padding: var(--spacing-300, 0.75rem) var(--collapsible-padding-x, var(--spacing-400, 1rem));
  font-size: var(--type-size-150, 0.9375rem);
  font-weight: var(--font-weight-semibold, 600);
  color: var(--collapsible-title-color, var(--color-text-primary, #171717));
  cursor: pointer;
  list-style: none;
}
.esa-collapsible--flush > .esa-collapsible__summary,
.esa-collapsible--flush > .esa-collapsible__body {
  padding-inline: 0;
}
.esa-collapsible__summary .esa-icon {
  flex-shrink: 0;
  color: var(--color-text-secondary, #404040);
}
.esa-collapsible__summary:after {
  content: "";
  width: 8px;
  height: 8px;
  border-right: 2px solid var(--color-text-tertiary, #737373);
  border-bottom: 2px solid var(--color-text-tertiary, #737373);
  transform: rotate(-45deg);
  transition: transform 0.15s ease;
  margin-left: auto;
}
.esa-badge {
  --_badge-bg: var(--badge-bg, var(--color-primary, #43608a));
  --_badge-text: var(--badge-text-color, var(--color-text-inverse, #fff));
  --_badge-height: var(--badge-height-md, 28px);
  --_badge-font-size: 13px;
  --_badge-padding-x: var(--spacing-200, 0.5rem);
  --_badge-min-width: var(--badge-height-md, 28px);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  height: var(--_badge-height);
  min-width: var(--_badge-min-width);
  padding-inline: var(--_badge-padding-x);
  border-radius: var(--badge-radius, var(--radius-100, 4px));
  background: var(--_badge-bg);
  color: var(--_badge-text);
  font-size: var(--_badge-font-size);
  font-weight: 600;
  line-height: 1;
  white-space: nowrap;
  box-sizing: border-box;
}
.esa-badge--sm {
  --_badge-height: var(--badge-height-sm, 22px);
  --_badge-font-size: 11px;
  --_badge-padding-x: var(--spacing-150, 0.375rem);
  --_badge-min-width: var(--badge-height-sm, 22px);
}
.esa-badge--secondary {
  --_badge-bg: var(--color-secondary, #65ba74);
  --_badge-text: var(--color-secondary-on-fill, #203c25);
}
.esa-icon-button {
  --_ib-size: var(--form-height-md, 40px);
  --_ib-bg-hover: var(--icon-button-bg-hover, color-mix(in srgb, currentColor 14%, transparent));
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: var(--_ib-size);
  height: var(--_ib-size);
  padding: 0;
  border: 0;
  border-radius: var(--radius-200, 8px);
  background: transparent;
  color: inherit;
  cursor: pointer;
  transition: background var(--transition-fast, 0.15s ease);
  -webkit-appearance: none;
  appearance: none;
}
.esa-icon-button--sm {
  --_ib-size: var(--form-height-sm, 32px);
}
.esa-collapsible[open] > .esa-collapsible__summary:after {
  transform: rotate(45deg);
}
.esa-collapsible__body {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-400, 1rem);
  padding: 0 var(--collapsible-padding-x, var(--spacing-400, 1rem)) var(--spacing-400, 1rem);
}
.esa-button {
  --_btn-height: var(--form-height-md, 40px);
  --_btn-padding-x: var(--form-padding-x-md, 16px);
  --_btn-font-size: var(--form-font-size-md, 14px);
  --_btn-radius: var(--form-radius-md, 6px);
  --_accent: var(--color-primary, #46a758);
  --_accent-hover: var(--color-primary-hover, #3e9b4f);
  --_on: var(--color-text-inverse, #ffffff);
  --_accent-text: var(--_accent);
  --_btn-tint-hover: color-mix(in srgb, var(--_accent) 8%, transparent);
  --_btn-tint-active: color-mix(in srgb, var(--_accent) 14%, transparent);
  display: inline-block;
}
.esa-button--sm {
  --_btn-height: var(--form-height-sm, 32px);
  --_btn-padding-x: var(--form-padding-x-sm, 12px);
  --_btn-font-size: var(--form-font-size-sm, 12px);
  --_btn-radius: var(--form-radius-sm, 4px);
}
.esa-button--color-danger {
  --_accent: var(--color-danger);
  --_accent-hover: var(--color-danger-hover);
  --_accent-text: var(--color-danger-strong);
}
.esa-button__native {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-200, 8px);
  width: 100%;
  height: var(--_btn-height);
  padding-inline: var(--_btn-padding-x);
  border: 1px solid transparent;
  border-radius: var(--_btn-radius);
  font-size: var(--_btn-font-size);
  font-family: var(--font-sans, system-ui, sans-serif);
  font-weight: var(--font-weight-medium, 500);
  line-height: 1;
  text-decoration: none;
  cursor: pointer;
  transition:
    background var(--transition-fast, 0.15s ease),
    border-color var(--transition-fast, 0.15s ease);
  -webkit-appearance: none;
  appearance: none;
}
.esa-button--sm .esa-button__native {
  height: auto;
  padding-block: var(--spacing-150, 6px);
}
.esa-button--appearance-fill .esa-button__native {
  background: var(--_accent);
  color: var(--_on);
  border-color: transparent;
}
.esa-button__label {
  white-space: nowrap;
}
.esa-button--appearance-outline .esa-button__native,
.esa-button--appearance-dashed .esa-button__native {
  background: transparent;
  color: var(--_accent-text);
  border-color: var(--_accent);
}
.esa-button--color-ghost .esa-button__native {
  background: transparent;
  color: var(--color-text-primary, #171717);
  border-color: transparent;
}
.esa-button--color-ghost.esa-button--appearance-outline .esa-button__native,
.esa-button--color-ghost.esa-button--appearance-dashed .esa-button__native {
  border-color: var(--color-border, #e5e5e5);
}
.esa-button--color-primary {
  --_accent-text: var(--color-primary-strong);
}
.spec {
  max-width: 1480px;
  margin: 0 auto;
  padding: var(--spacing-700) var(--spacing-500) var(--spacing-800);
  display: flex;
  flex-direction: column;
  gap: var(--spacing-700);
}
.spec__head {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
}
.spec__title {
  margin: 0;
  font-family: var(--font-decorative);
  font-size: 2rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.spec__intro {
  margin: 0;
  max-width: 86ch;
  font-size: var(--type-size-200, 1rem);
  line-height: 1.6;
  color: var(--color-text-secondary);
}
.spec__intro strong {
  color: var(--color-text-primary);
  font-weight: var(--font-weight-semibold);
}
.v2 {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-500);
}
.v2__head {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
}
.v2__title {
  margin: 0;
  font-size: 1.5rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.v2__changes {
  margin: 0;
  padding-left: 1.25rem;
  max-width: 86ch;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-200);
}
.v2__changes li {
  font-size: 1rem;
  line-height: 1.55;
  color: var(--color-text-secondary);
}
.v2__changes strong {
  color: var(--color-text-primary);
  font-weight: var(--font-weight-semibold);
}
.v2__pair {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(360px, 1fr));
  gap: var(--spacing-500);
  align-items: start;
  max-width: 1000px;
}
.mockup {
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-200);
}
.v2__pair .mockup {
  max-width: 460px;
  width: 100%;
  justify-self: center;
}
.mockup__case {
  font-size: 0.875rem;
  font-weight: var(--font-weight-semibold);
  line-height: 1.5;
  color: var(--color-text-secondary);
}
.drawer {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
  box-shadow: 0 12px 32px #0000001a;
  overflow: hidden;
}
.drawer__head {
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding: var(--spacing-400);
  border-bottom: 1px solid var(--color-border);
}
.drawer__headrow {
  display: flex;
  align-items: center;
  gap: var(--spacing-300);
}
.drawer__title {
  margin: 0;
  font-size: var(--type-size-400);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.bcn-status-chip[data-status="provisional-block"],
.bcn-status-chip[data-status="provisional-block"] .bcn-status-chip__dot {
  background: var(--color-surface);
  box-shadow: inset 0 0 0 1.5px var(--st-provisional-block);
}
.drawer__sub {
  margin: 0;
  font-size: 0.875rem;
  color: var(--color-text-secondary);
}
.band {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--spacing-200) var(--spacing-300);
  padding: var(--spacing-250) var(--spacing-400);
  background: var(--color-background);
  border-bottom: 1px solid var(--color-border);
}
.drawer__body {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-400);
  padding: var(--spacing-400);
}
.decide {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-200);
  padding: var(--spacing-250) var(--spacing-300);
  border-radius: var(--radius-200);
  background: var(--color-background);
  border: 1px solid var(--color-border);
}
.decide--prov {
  background: color-mix(in srgb, var(--st-provisional-block) 6%, transparent);
  border-color: color-mix(in srgb, var(--st-provisional-block) 45%, transparent);
  --color-danger: var(--st-provisional-block);
}
.decide__line {
  margin: 0;
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  line-height: 1.45;
  color: var(--color-text-primary);
}
.decide__line--fact {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--spacing-250);
}
.decide--prov .decide__line {
  color: color-mix(in srgb, var(--st-provisional-block) 72%, #1a1a1a);
}
.obs-id {
  flex-shrink: 0;
  font-family: var(--font-mono);
  font-size: 0.8125rem;
  font-weight: 500;
  padding: 1px var(--spacing-200);
  border-radius: var(--radius-100);
  background: var(--color-surface);
  border: 1px solid color-mix(in srgb, var(--st-provisional-block) 45%, transparent);
  color: color-mix(in srgb, var(--st-provisional-block) 72%, #1a1a1a);
  white-space: nowrap;
}
.decide__actions {
  display: flex;
  justify-content: flex-end;
  gap: var(--spacing-200);
}
.drawer__section {
  display: flex;
  align-items: center;
  gap: var(--spacing-200);
  margin: 0 0 var(--spacing-300);
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.drawer__section .esa-icon {
  flex-shrink: 0;
  color: var(--color-text-secondary);
}
.board {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--spacing-200);
}
.board__cell--btn {
  width: 100%;
  cursor: pointer;
  text-align: left;
  font-family: inherit;
  border: 1px solid var(--color-border-light);
  background: var(--color-surface);
  transition:
    border-color 0.12s ease,
    background 0.12s ease;
}
.board__cell {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: var(--spacing-150);
  padding: var(--spacing-250) var(--spacing-300);
  border: 1px solid var(--color-border-light);
  border-radius: var(--radius-200);
  background: var(--color-surface);
}
.board__cellhead {
  display: flex;
  align-items: center;
  gap: var(--spacing-150);
  width: 100%;
}
.board__dim {
  font-size: 0.875rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.board__cellhead .board__dim {
  flex: 1;
  min-width: 0;
}
.board__chev {
  display: inline-flex;
  color: var(--color-text-tertiary);
}
.board__meta {
  font-size: 0.8125rem;
  color: var(--color-text-tertiary);
}
.unreviewed {
  display: inline-flex;
  align-items: center;
  padding: 2px var(--spacing-250);
  border: 1px dashed var(--color-border-strong);
  border-radius: var(--radius-full);
  font-size: var(--type-size-100);
  font-weight: var(--font-weight-medium);
  color: var(--color-text-tertiary);
  white-space: nowrap;
}
.drawer__more {
  display: flex;
  flex-direction: column;
}
.drawer__more .esa-collapsible + .esa-collapsible {
  border-top: 1px solid var(--color-border-light);
}
.drawer__foot {
  display: flex;
  justify-content: flex-end;
  gap: var(--spacing-200);
  padding: var(--spacing-300) var(--spacing-400);
  border-top: 1px solid var(--color-border);
  background: var(--color-surface);
}
.decide__row {
  display: flex;
  align-items: center;
  gap: var(--spacing-250);
}
.decide__row--warn .esa-icon {
  flex-shrink: 0;
  color: color-mix(in srgb, var(--st-blocked) 72%, #1a1a1a);
}
.decide__warntext {
  flex: 1;
  min-width: 0;
  font-size: 0.875rem;
  font-weight: var(--font-weight-semibold);
  line-height: 1.45;
  color: color-mix(in srgb, var(--st-blocked) 72%, #1a1a1a);
}
.v2__sub {
  margin: var(--spacing-300) 0 0;
  font-size: 1.1875rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.stack {
  position: relative;
  width: 100%;
  max-width: 540px;
}
.stack__parent {
  position: relative;
  width: calc(100% - 72px);
}
.band--4 {
  grid-template-columns: repeat(4, 1fr);
}
.band__alert {
  font-size: var(--form-font-size-md);
  font-weight: var(--font-weight-semibold);
  color: color-mix(in srgb, var(--st-blocked) 72%, #1a1a1a);
}
.decide--blocked {
  background: color-mix(in srgb, var(--st-blocked) 10%, transparent);
  border-color: color-mix(in srgb, var(--st-blocked) 30%, transparent);
}
.decide--blocked .decide__line {
  color: color-mix(in srgb, var(--st-blocked) 72%, #1a1a1a);
}
.board__cell--btn[data-active] {
  border-color: var(--color-primary);
  box-shadow: inset 0 0 0 1px var(--color-primary);
  background: var(--color-primary-subtle);
}
.stack__parent:after {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: var(--radius-300);
  background: #0d111438;
  z-index: 4;
  pointer-events: none;
}
.stack__child {
  position: absolute;
  top: 0;
  right: 0;
  bottom: 0;
  width: calc(100% - 72px);
  display: flex;
  flex-direction: column;
  box-shadow: -16px 0 40px #00000038;
  z-index: 5;
}
.drawer__close {
  margin-left: auto;
  color: var(--color-text-secondary);
}
.stack__child .drawer__body {
  flex: 1;
}
.child__bar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-300);
}
.child__count {
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.revs {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
}
.rev {
  position: relative;
  display: grid;
  grid-template-columns: 16px 1fr;
  column-gap: var(--spacing-250);
  padding-bottom: var(--spacing-400);
}
.rev:not(:last-child):before {
  content: "";
  position: absolute;
  left: 7px;
  top: 20px;
  bottom: 2px;
  width: 2px;
  background: var(--color-border);
}
.rev__dot {
  width: 16px;
  height: 16px;
  border-radius: var(--radius-full);
  margin-top: 2px;
  z-index: 1;
  background: var(--color-surface);
  border: 2px solid var(--color-border-strong);
}
.rev[data-kind="scheduled"] .rev__dot {
  border-color: var(--st-survey-scheduled);
}
.rev__main {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-150);
  min-width: 0;
}
.rev__head {
  display: flex;
  align-items: baseline;
  flex-wrap: wrap;
  gap: var(--spacing-200);
  margin: 0;
  font-size: 1rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.rev__when {
  font-size: 0.875rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-secondary);
}
.rev__chiprow {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--spacing-200);
}
.rev__note {
  margin: 0;
  font-size: 0.9375rem;
  line-height: 1.55;
  color: var(--color-text-secondary);
}
.rev:last-child {
  padding-bottom: 0;
}
.rev[data-kind="blocked"] .rev__dot {
  background: var(--st-blocked);
  border-color: var(--st-blocked);
}
.rev__until {
  font-size: 0.875rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-secondary);
}
.rev__current {
  display: inline-flex;
  align-items: center;
  padding: 1px var(--spacing-200);
  border-radius: var(--radius-full);
  background: color-mix(in srgb, var(--color-primary) 10%, transparent);
  border: 1px solid color-mix(in srgb, var(--color-primary) 30%, transparent);
  font-size: 0.75rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-primary);
  white-space: nowrap;
}
.model-note {
  max-width: 86ch;
  padding: var(--spacing-400) var(--spacing-500);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
  display: flex;
  flex-direction: column;
  gap: var(--spacing-200);
}
.model-note__title {
  margin: 0;
  font-size: 1rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.model-note__text {
  margin: 0;
  font-size: 0.9375rem;
  line-height: 1.6;
  color: var(--color-text-secondary);
}
.model-note__text code {
  font-family: var(--font-mono);
  font-size: 0.875em;
  padding: 1px 5px;
  border-radius: var(--radius-100);
  background: var(--color-background);
  border: 1px solid var(--color-border-light);
}
.model-note__text strong {
  color: var(--color-text-primary);
  font-weight: var(--font-weight-semibold);
}
.evaluate {
  max-width: 86ch;
  padding: var(--spacing-500);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
}
.evaluate__title {
  margin: 0;
  font-size: 1.25rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.evaluate__list {
  margin: 0;
  padding-left: 1.5rem;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-250);
}
.evaluate__list li {
  font-size: 1rem;
  line-height: 1.55;
  color: var(--color-text-secondary);
}
.round1 {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-500);
  padding-top: var(--spacing-600);
  border-top: 1px solid var(--color-border);
}
.round1__head {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-200);
}
.round1__title {
  margin: 0;
  font-size: 1.5rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.round1__line {
  margin: 0;
  max-width: 86ch;
  font-size: 1rem;
  line-height: 1.55;
  color: var(--color-text-secondary);
}
.concepts {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(360px, 1fr));
  gap: var(--spacing-700) var(--spacing-500);
  align-items: start;
}
.concept {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-400);
  max-width: 460px;
  width: 100%;
  justify-self: center;
}
.concept__thesis {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-250);
}
.concept__name {
  display: flex;
  align-items: center;
  gap: var(--spacing-250);
  margin: 0;
  font-size: 1.25rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.concept__num {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  border-radius: var(--radius-full);
  background: var(--color-primary);
  color: #fff;
  font-size: 1rem;
  font-weight: var(--font-weight-semibold);
  flex-shrink: 0;
}
.concept__line {
  margin: 0;
  font-size: 1rem;
  line-height: 1.5;
  color: var(--color-text-secondary);
}
.concept__pt {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-100);
}
.concept__pt-label {
  margin: var(--spacing-150) 0 0;
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.concept__pt ul {
  margin: 0;
  padding-left: 1.25rem;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-100);
}
.concept__pt li {
  font-size: 0.9375rem;
  line-height: 1.5;
  color: var(--color-text-secondary);
}
.action {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-250);
  padding: var(--spacing-400);
  border-radius: var(--radius-300);
  background: var(--color-background);
  border: 1px solid var(--color-border);
}
.action--provisional {
  background: color-mix(in srgb, var(--st-provisional-block) 6%, transparent);
  border: 1px solid color-mix(in srgb, var(--st-provisional-block) 45%, transparent);
}
.action__title {
  margin: 0;
  font-size: 1.0625rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.action--provisional .action__title {
  color: color-mix(in srgb, var(--st-provisional-block) 72%, #1a1a1a);
}
.action__text {
  margin: 0;
  font-size: 0.9375rem;
  line-height: 1.55;
  color: var(--color-text-secondary);
}
.action__facts {
  margin: 0;
  font-size: 0.875rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-secondary);
}
.action__btns {
  display: flex;
  gap: var(--spacing-200);
  margin-top: var(--spacing-100);
}
.rows {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-200);
}
.conflict {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-300);
  padding: var(--spacing-250) var(--spacing-300);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
}
.conflict__main {
  display: flex;
  flex-direction: column;
  gap: 2px;
  min-width: 0;
  flex: 1;
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.conflict__sub {
  font-size: 0.8125rem;
  font-weight: var(--font-weight-regular);
  color: var(--color-text-tertiary);
}
.conflict__meta {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 2px;
  font-size: 0.875rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
  white-space: nowrap;
}
.action__conflict {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-150);
  margin: 0;
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  line-height: 1.45;
  color: color-mix(in srgb, var(--st-blocked) 72%, #1a1a1a);
}
.action__conflict .esa-icon {
  flex-shrink: 0;
  margin-top: 2px;
}
.strip {
  display: flex;
  align-items: center;
  gap: var(--spacing-250);
  padding: var(--spacing-250) var(--spacing-300);
  background: var(--color-background);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-200);
}
.strip .esa-icon {
  flex-shrink: 0;
  color: color-mix(in srgb, var(--st-blocked) 72%, #1a1a1a);
}
.strip__text {
  font-size: 0.875rem;
  line-height: 1.45;
  color: var(--color-text-secondary);
}
.strip__text strong {
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.disc-tabs {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: var(--spacing-150);
}
.disc-tabs [role="tab"] {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--spacing-100);
  padding: var(--spacing-200) var(--spacing-100);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-200);
  background: var(--color-surface);
  font-family: inherit;
  cursor: pointer;
  transition:
    border-color 0.12s ease,
    background 0.12s ease;
}
.disc-tabs__dot {
  width: 10px;
  height: 10px;
  border-radius: var(--radius-full);
  flex-shrink: 0;
}
.disc-tabs__label {
  font-size: 0.875rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-primary);
}
.disc-tabs__dot[data-none="true"] {
  background: var(--color-surface);
  border: 1px dashed var(--color-border-strong);
}
.disc-tabs [role="tab"][aria-selected="true"] {
  border-color: var(--color-primary);
  background: var(--color-primary-subtle);
  box-shadow: inset 0 0 0 1px var(--color-primary);
}
.disc-panel {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
  padding: var(--spacing-400);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
  background: var(--color-surface);
}
.disc-panel[hidden] {
  display: none;
}
.disc-panel__head {
  display: flex;
  align-items: center;
  gap: var(--spacing-300);
}
.disc-panel__when {
  font-size: 0.875rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-secondary);
}
.kv-text {
  font-size: 0.9375rem;
  line-height: 1.5;
  color: var(--color-text-secondary);
}
.disc-panel__warn {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-150);
  margin: 0;
  font-size: 0.875rem;
  font-weight: var(--font-weight-semibold);
  line-height: 1.45;
  color: color-mix(in srgb, var(--st-blocked) 72%, #1a1a1a);
}
.disc-panel__warn .esa-icon {
  flex-shrink: 0;
  margin-top: 1px;
}
.disc-panel__foot {
  display: flex;
  gap: var(--spacing-200);
  margin-top: var(--spacing-100);
}
.steps {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
}
.step {
  position: relative;
  display: grid;
  grid-template-columns: 24px 1fr;
  column-gap: var(--spacing-300);
  padding-bottom: var(--spacing-400);
}
.step:not(:last-child):before {
  content: "";
  position: absolute;
  left: 11px;
  top: 28px;
  bottom: 4px;
  width: 2px;
  background: var(--color-border);
}
.step__dot {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  border-radius: var(--radius-full);
  background: var(--color-surface);
  border: 2px solid var(--color-border-strong);
  margin-top: 0;
  z-index: 1;
}
.step[data-state="done"] .step__dot {
  background: var(--color-primary);
  border-color: var(--color-primary);
}
.step[data-state="done"] .step__dot:after {
  content: "";
  width: 9px;
  height: 5px;
  border-left: 2px solid #fff;
  border-bottom: 2px solid #fff;
  transform: rotate(-45deg);
  margin-top: -2px;
}
.step__content {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-150);
  min-width: 0;
  padding-top: 2px;
}
.step__title {
  display: flex;
  align-items: baseline;
  flex-wrap: wrap;
  gap: var(--spacing-200);
  margin: 0;
  font-size: 1rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.step__when {
  font-size: 0.875rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-secondary);
}
.step__text {
  margin: 0;
  font-size: 0.9375rem;
  line-height: 1.5;
  color: var(--color-text-secondary);
}
.step[data-state="scheduled"] .step__dot {
  border-color: var(--st-survey-scheduled);
}
.step[data-state="live-red"] .step__dot {
  border-color: var(--st-provisional-block);
  box-shadow: 0 0 0 4px color-mix(in srgb, var(--st-provisional-block) 18%, transparent);
}
.step[data-state="live-red"] .step__dot:after {
  content: "";
  width: 8px;
  height: 8px;
  border-radius: var(--radius-full);
  background: var(--st-provisional-block);
}
.step[data-state="live-red"] .step__when {
  color: color-mix(in srgb, var(--st-provisional-block) 72%, #1a1a1a);
}
.check {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
}
.check__row {
  display: grid;
  grid-template-columns: 12px 1fr auto;
  column-gap: var(--spacing-250);
  row-gap: 2px;
  align-items: center;
  padding: var(--spacing-200) 0;
}
.check__dot {
  width: 10px;
  height: 10px;
  border-radius: var(--radius-full);
  justify-self: center;
}
.check__dim {
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.check__state {
  grid-column: 2 / -1;
  font-size: 0.875rem;
  color: var(--color-text-secondary);
}
.check__row + .check__row {
  border-top: 1px solid var(--color-border-light);
}
.check__dot[data-none="true"] {
  background: var(--color-surface);
  border: 1px dashed var(--color-border-strong);
}
.action--instep {
  padding: var(--spacing-300);
  margin-top: var(--spacing-250);
}
.action__text strong {
  color: color-mix(in srgb, var(--st-provisional-block) 72%, #1a1a1a);
  font-weight: var(--font-weight-semibold);
}
.step[data-state="future"] .step__dot {
  border-style: dashed;
  border-color: var(--color-border-strong);
}
.step:last-child {
  padding-bottom: 0;
}
.step__flag {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-150);
  margin: 0;
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  line-height: 1.45;
  color: color-mix(in srgb, var(--st-blocked) 72%, #1a1a1a);
}
.step__flag .esa-icon {
  flex-shrink: 0;
  margin-top: 2px;
}
.step__act {
  display: flex;
  gap: var(--spacing-200);
  margin-top: var(--spacing-100);
}
.survey__link {
  font-size: 0.9375rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-secondary);
  text-decoration: none;
  cursor: pointer;
}
.step[data-state="live"] .step__dot {
  border-color: var(--st-survey-scheduled);
  box-shadow: 0 0 0 4px color-mix(in srgb, var(--st-survey-scheduled) 22%, transparent);
}
.step[data-state="live"] .step__dot:after {
  content: "";
  width: 8px;
  height: 8px;
  border-radius: var(--radius-full);
  background: var(--st-survey-scheduled);
}
.check__act {
  grid-row: 1;
  grid-column: 3;
}

full.css:
:root,
[data-theme="beacon"] {
  --badge-bg: #005862;
  --badge-height-md: 28px;
  --badge-height-sm: 22px;
  --badge-radius: 0.25rem;
  --badge-text-color: #fcfcfc;
  --collapsible-bg: #fcfcfc;
  --collapsible-border-color: #dcdcdc;
  --collapsible-padding-x: 1rem;
  --collapsible-radius: 0.5rem;
  --collapsible-title-color: #3d3d3d;
  --color-background: #fafafa;
  --color-border: #dcdcdc;
  --color-border-light: #efefef;
  --color-border-strong: #bdbdbd;
  --color-danger: #e5484d;
  --color-danger-hover: #dc3e42;
  --color-danger-strong: #ce2c31;
  --color-primary: #005862;
  --color-primary-hover: #00474f;
  --color-primary-strong: #2a7e3b;
  --color-primary-subtle: #effefb;
  --color-secondary: #00918b;
  --color-secondary-on-fill: #203c25;
  --color-surface: #fcfcfc;
  --color-text-inverse: #fcfcfc;
  --color-text-link: #005862;
  --color-text-primary: #3d3d3d;
  --color-text-secondary: #525252;
  --color-text-tertiary: #656565;
  --font-decorative: "Besley", serif;
  --font-mono: "Roboto Mono", ui-monospace, monospace;
  --font-sans: "DM Sans", sans-serif;
  --font-weight-medium: 450;
  --font-weight-regular: 350;
  --font-weight-semibold: 550;
  --form-font-size-md: clamp(0.75rem, 0.66rem + 0.44vw, 0.9375rem);
  --form-font-size-sm: clamp(0.625rem, 0.56rem + 0.32vw, 0.75rem);
  --form-height-md: 36px;
  --form-height-sm: 28px;
  --form-label-color: #525252;
  --form-padding-x-md: 0.75rem;
  --form-padding-x-sm: 0.625rem;
  --form-radius-md: 0.25rem;
  --form-radius-sm: 0.25rem;
  --icon-button-bg-hover: color-mix(in srgb, currentColor 14%, transparent);
  --icon-size-md: 20px;
  --icon-size-medium: 20px;
  --icon-size-sm: 16px;
  --icon-size-small: 16px;
  --radius-100: 0.25rem;
  --radius-200: 0.5rem;
  --radius-300: 0.5rem;
  --radius-full: 9999px;
  --spacing-100: 0.25rem;
  --spacing-150: 0.375rem;
  --spacing-200: 0.5rem;
  --spacing-250: 0.625rem;
  --spacing-300: 0.75rem;
  --spacing-400: 1rem;
  --spacing-500: 1.5rem;
  --spacing-600: 2rem;
  --spacing-700: 3rem;
  --spacing-800: 4rem;
  --st-blocked: #d73027;
  --st-provisional-block: #d73027;
  --st-survey-scheduled: #74add1;
  --transition-fast: 0.15s ease;
  --type-size-100: clamp(0.625rem, 0.56rem + 0.32vw, 0.75rem);
  --type-size-150: clamp(0.6875rem, 0.61rem + 0.38vw, 0.875rem);
  --type-size-200: clamp(0.75rem, 0.66rem + 0.44vw, 0.9375rem);
  --type-size-400: clamp(1rem, 0.88rem + 0.6vw, 1.25rem);
}

*,
*:before,
*:after {
  box-sizing: border-box;
}
body {
  margin: 0;
  font-family: var(--font-sans, system-ui, sans-serif);
  font-weight: var(--font-weight-regular, 350);
  color: var(--color-text-primary, #3d3d3d);
  background: var(--color-surface, #fff);
  -webkit-font-smoothing: antialiased;
}
:where(h1, h2, h3, h4, h5, h6, p, figure, blockquote, dl, dd, ul, ol, pre) {
  margin: 0;
}
button {
  font-family: inherit;
  cursor: pointer;
  background: none;
  border: 0;
}
.stack {
  --gap: var(--spacing-400, 1rem);
  display: flex;
  flex-direction: column;
  gap: var(--gap);
}
a {
  color: var(--color-text-link, #005862);
  text-decoration: none;
}
:host {
  all: initial;
}
.host-root {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 2147483000;
  font-family: system-ui, sans-serif;
}
.host-root > * {
  pointer-events: auto;
}
.launch {
  position: fixed;
  bottom: 22px;
  left: 22px;
  display: inline-flex;
  align-items: center;
  gap: 9px;
  padding: 13px 19px;
  border-radius: 999px;
  color: #fff;
  cursor: pointer;
  font-size: 15px;
  font-weight: 600;
  letter-spacing: 0.01em;
  border: 1px solid #3d6fd6;
  background: linear-gradient(180deg, #1f6feb, #1551c4);
  box-shadow:
    0 10px 28px -8px rgba(31, 111, 235, 0.65),
    inset 0 1px 0 rgba(255, 255, 255, 0.18);
  transition:
    transform 0.15s ease,
    box-shadow 0.15s ease,
    filter 0.15s ease;
}
.launch svg {
  flex: none;
}
.panel {
  position: fixed;
  top: 18px;
  right: 18px;
  bottom: 18px;
  width: min(720px, 94vw);
  display: flex;
  flex-direction: column;
  color: #ffffff;
  border-radius: 16px;
  background: linear-gradient(155deg, rgba(26, 31, 40, 0.74), rgba(11, 15, 21, 0.86));
  backdrop-filter: blur(26px) saturate(150%);
  -webkit-backdrop-filter: blur(26px) saturate(150%);
  border: 1px solid rgba(255, 255, 255, 0.15);
  box-shadow:
    0 28px 70px -18px rgba(0, 0, 0, 0.62),
    inset 0 1px 0 rgba(255, 255, 255, 0.1);
  font-size: 12.5px;
  overflow: hidden;
  /* slide in from the right */
  transform: translateX(calc(100% + 32px));
  opacity: 0;
  visibility: hidden;
  transition:
    transform 0.3s cubic-bezier(0.4, 0, 0.2, 1),
    opacity 0.22s ease,
    visibility 0s linear 0.3s;
}
.head {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 13px 16px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.09);
}
.head strong {
  font-size: 14px;
}
.head .sub {
  flex: 1;
  color: #ccd5e0;
  font-size: 12px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.x {
  border: 0;
  background: none;
  color: #c4cdd8;
  font-size: 20px;
  line-height: 1;
  cursor: pointer;
}
.picker {
  padding: 12px 16px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.09);
}
.chips {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}
.chip {
  padding: 5px 12px;
  border-radius: 999px;
  border: 1px solid rgba(255, 255, 255, 0.14);
  background: rgba(255, 255, 255, 0.04);
  color: #eef2f6;
  font: inherit;
  font-size: 12.5px;
  cursor: pointer;
  white-space: nowrap;
  transition:
    border-color 0.12s ease,
    background 0.12s ease,
    color 0.12s ease;
}
.chip.on {
  background: rgba(31, 111, 235, 0.28);
  border-color: #4493f8;
  color: #fff;
  font-weight: 600;
}
.tabs {
  display: flex;
  gap: 4px;
  padding: 9px 14px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.09);
}
.tabs button {
  padding: 5px 12px;
  border: 0;
  border-radius: 6px;
  background: none;
  color: #ccd5e0;
  font: inherit;
  font-size: 12.5px;
  cursor: pointer;
}
.tabs button.on {
  background: rgba(255, 255, 255, 0.12);
  color: #fff;
}
.body {
  overflow: auto;
  padding: 13px 16px;
  flex: 1;
}
.hint {
  margin: 0;
  color: #c4cdd8;
  line-height: 1.6;
}
.footer {
  position: relative;
  display: flex;
  justify-content: flex-end;
  gap: 8px;
  padding: 11px 16px;
  border-top: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(0, 0, 0, 0.18);
}
[hidden] {
  display: none !important;
}
.cpreview {
  position: absolute;
  left: 16px;
  right: 16px;
