  padding: var(--spacing-400) var(--spacing-500);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
  display: flex;
  flex-direction: column;
  gap: var(--spacing-200);
}
.model-note__title {
  margin: 0;
  font-size: 1rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.model-note__text {
  margin: 0;
  font-size: 0.9375rem;
  line-height: 1.6;
  color: var(--color-text-secondary);
}
.model-note__text code {
  font-family: var(--font-mono);
  font-size: 0.875em;
  padding: 1px 5px;
  border-radius: var(--radius-100);
  background: var(--color-background);
  border: 1px solid var(--color-border-light);
}
.model-note__text strong {
  color: var(--color-text-primary);
  font-weight: var(--font-weight-semibold);
}
.evaluate {
  max-width: 86ch;
  padding: var(--spacing-500);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
}
.evaluate__title {
  margin: 0;
  font-size: 1.25rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.evaluate__list {
  margin: 0;
  padding-left: 1.5rem;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-250);
}
.evaluate__list li {
  font-size: 1rem;
  line-height: 1.55;
  color: var(--color-text-secondary);
}
.round1 {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-500);
  padding-top: var(--spacing-600);
  border-top: 1px solid var(--color-border);
}
.round1__head {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-200);
}
.round1__title {
  margin: 0;
  font-size: 1.5rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.round1__line {
  margin: 0;
  max-width: 86ch;
  font-size: 1rem;
  line-height: 1.55;
  color: var(--color-text-secondary);
}
.concepts {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(360px, 1fr));
  gap: var(--spacing-700) var(--spacing-500);
  align-items: start;
}
.concept {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-400);
  max-width: 460px;
  width: 100%;
  justify-self: center;
}
.concept__thesis {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-250);
}
.concept__name {
  display: flex;
  align-items: center;
  gap: var(--spacing-250);
  margin: 0;
  font-size: 1.25rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.concept__num {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  border-radius: var(--radius-full);
  background: var(--color-primary);
  color: #fff;
  font-size: 1rem;
  font-weight: var(--font-weight-semibold);
  flex-shrink: 0;
}
.concept__line {
  margin: 0;
  font-size: 1rem;
  line-height: 1.5;
  color: var(--color-text-secondary);
}
.concept__pt {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-100);
}
.concept__pt-label {
  margin: var(--spacing-150) 0 0;
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.concept__pt ul {
  margin: 0;
  padding-left: 1.25rem;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-100);
}
.concept__pt li {
  font-size: 0.9375rem;
  line-height: 1.5;
  color: var(--color-text-secondary);
}
.action {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-250);
  padding: var(--spacing-400);
  border-radius: var(--radius-300);
  background: var(--color-background);
  border: 1px solid var(--color-border);
}
.action--provisional {
  background: color-mix(in srgb, var(--st-provisional-block) 6%, transparent);
  border: 1px solid color-mix(in srgb, var(--st-provisional-block) 45%, transparent);
}
.action__title {
  margin: 0;
  font-size: 1.0625rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.action--provisional .action__title {
  color: color-mix(in srgb, var(--st-provisional-block) 72%, #1a1a1a);
}
.action__text {
  margin: 0;
  font-size: 0.9375rem;
  line-height: 1.55;
  color: var(--color-text-secondary);
}
.action__facts {
  margin: 0;
  font-size: 0.875rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-secondary);
}
.action__btns {
  display: flex;
  gap: var(--spacing-200);
  margin-top: var(--spacing-100);
}
.rows {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-200);
}
.conflict {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-300);
  padding: var(--spacing-250) var(--spacing-300);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
}
.conflict__main {
  display: flex;
  flex-direction: column;
  gap: 2px;
  min-width: 0;
  flex: 1;
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.conflict__sub {
  font-size: 0.8125rem;
  font-weight: var(--font-weight-regular);
  color: var(--color-text-tertiary);
}
.conflict__meta {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 2px;
  font-size: 0.875rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
  white-space: nowrap;
}
.action__conflict {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-150);
  margin: 0;
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  line-height: 1.45;
  color: color-mix(in srgb, var(--st-blocked) 72%, #1a1a1a);
}
.action__conflict .esa-icon {
  flex-shrink: 0;
  margin-top: 2px;
}
.strip {
  display: flex;
  align-items: center;
  gap: var(--spacing-250);
  padding: var(--spacing-250) var(--spacing-300);
  background: var(--color-background);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-200);
}
.strip .esa-icon {
  flex-shrink: 0;
  color: color-mix(in srgb, var(--st-blocked) 72%, #1a1a1a);
}
.strip__text {
  font-size: 0.875rem;
  line-height: 1.45;
  color: var(--color-text-secondary);
}
.strip__text strong {
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.disc-tabs {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: var(--spacing-150);
}
.disc-tabs [role="tab"] {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--spacing-100);
  padding: var(--spacing-200) var(--spacing-100);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-200);
  background: var(--color-surface);
  font-family: inherit;
  cursor: pointer;
  transition:
    border-color 0.12s ease,
    background 0.12s ease;
}
.disc-tabs__dot {
  width: 10px;
  height: 10px;
  border-radius: var(--radius-full);
  flex-shrink: 0;
}
.disc-tabs__label {
  font-size: 0.875rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-primary);
}
.disc-tabs__dot[data-none="true"] {
  background: var(--color-surface);
  border: 1px dashed var(--color-border-strong);
}
.disc-tabs [role="tab"][aria-selected="true"] {
  border-color: var(--color-primary);
  background: var(--color-primary-subtle);
  box-shadow: inset 0 0 0 1px var(--color-primary);
}
.disc-panel {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
  padding: var(--spacing-400);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
  background: var(--color-surface);
}
.disc-panel[hidden] {
  display: none;
}
.disc-panel__head {
  display: flex;
  align-items: center;
  gap: var(--spacing-300);
}
.disc-panel__when {
  font-size: 0.875rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-secondary);
}
.kv-text {
  font-size: 0.9375rem;
  line-height: 1.5;
  color: var(--color-text-secondary);
}
.disc-panel__warn {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-150);
  margin: 0;
  font-size: 0.875rem;
  font-weight: var(--font-weight-semibold);
  line-height: 1.45;
  color: color-mix(in srgb, var(--st-blocked) 72%, #1a1a1a);
}
.disc-panel__warn .esa-icon {
  flex-shrink: 0;
  margin-top: 1px;
}
.disc-panel__foot {
  display: flex;
  gap: var(--spacing-200);
  margin-top: var(--spacing-100);
}
.steps {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
}
.step {
  position: relative;
  display: grid;
  grid-template-columns: 24px 1fr;
  column-gap: var(--spacing-300);
  padding-bottom: var(--spacing-400);
}
.step:not(:last-child):before {
  content: "";
  position: absolute;
  left: 11px;
  top: 28px;
  bottom: 4px;
  width: 2px;
  background: var(--color-border);
}
.step__dot {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  border-radius: var(--radius-full);
  background: var(--color-surface);
  border: 2px solid var(--color-border-strong);
  margin-top: 0;
  z-index: 1;
}
.step[data-state="done"] .step__dot {
  background: var(--color-primary);
  border-color: var(--color-primary);
}
.step[data-state="done"] .step__dot:after {
  content: "";
  width: 9px;
  height: 5px;
  border-left: 2px solid #fff;
  border-bottom: 2px solid #fff;
  transform: rotate(-45deg);
  margin-top: -2px;
}
.step__content {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-150);
  min-width: 0;
  padding-top: 2px;
}
.step__title {
  display: flex;
  align-items: baseline;
  flex-wrap: wrap;
  gap: var(--spacing-200);
  margin: 0;
  font-size: 1rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.step__when {
  font-size: 0.875rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-secondary);
}
.step__text {
  margin: 0;
  font-size: 0.9375rem;
  line-height: 1.5;
  color: var(--color-text-secondary);
}
.step[data-state="scheduled"] .step__dot {
  border-color: var(--st-survey-scheduled);
}
.step[data-state="live-red"] .step__dot {
  border-color: var(--st-provisional-block);
  box-shadow: 0 0 0 4px color-mix(in srgb, var(--st-provisional-block) 18%, transparent);
}
.step[data-state="live-red"] .step__dot:after {
  content: "";
  width: 8px;
  height: 8px;
  border-radius: var(--radius-full);
  background: var(--st-provisional-block);
}
.step[data-state="live-red"] .step__when {
  color: color-mix(in srgb, var(--st-provisional-block) 72%, #1a1a1a);
}
.check {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
}
.check__row {
  display: grid;
  grid-template-columns: 12px 1fr auto;
  column-gap: var(--spacing-250);
  row-gap: 2px;
  align-items: center;
  padding: var(--spacing-200) 0;
}
.check__dot {
  width: 10px;
  height: 10px;
  border-radius: var(--radius-full);
  justify-self: center;
}
.check__dim {
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.check__state {
  grid-column: 2 / -1;
  font-size: 0.875rem;
  color: var(--color-text-secondary);
}
.check__row + .check__row {
  border-top: 1px solid var(--color-border-light);
}
.check__dot[data-none="true"] {
  background: var(--color-surface);
  border: 1px dashed var(--color-border-strong);
}
.action--instep {
  padding: var(--spacing-300);
  margin-top: var(--spacing-250);
}
.action__text strong {
  color: color-mix(in srgb, var(--st-provisional-block) 72%, #1a1a1a);
  font-weight: var(--font-weight-semibold);
}
.step[data-state="future"] .step__dot {
  border-style: dashed;
  border-color: var(--color-border-strong);
}
.step:last-child {
  padding-bottom: 0;
}
.step__flag {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-150);
  margin: 0;
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  line-height: 1.45;
  color: color-mix(in srgb, var(--st-blocked) 72%, #1a1a1a);
}
.step__flag .esa-icon {
  flex-shrink: 0;
  margin-top: 2px;
}
.step__act {
  display: flex;
  gap: var(--spacing-200);
  margin-top: var(--spacing-100);
}
.survey__link {
  font-size: 0.9375rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-secondary);
  text-decoration: none;
  cursor: pointer;
}
.step[data-state="live"] .step__dot {
  border-color: var(--st-survey-scheduled);
  box-shadow: 0 0 0 4px color-mix(in srgb, var(--st-survey-scheduled) 22%, transparent);
}
.step[data-state="live"] .step__dot:after {
  content: "";
  width: 8px;
  height: 8px;
  border-radius: var(--radius-full);
  background: var(--st-survey-scheduled);
}
.check__act {
  grid-row: 1;
  grid-column: 3;
}
